const { Client } = require('pg');
const item = $input.first().json;
const client = new Client({ host: $env.APP_PG_HOST || 'db', port: parseInt($env.APP_PG_PORT || '5432'), user: $env.APP_PG_USER, password: $env.APP_PG_PASSWORD, database: ($env.APP_PG_DATABASE || 'ragkb_app') });
await client.connect();
try {
  const estResult = await client.query('SELECT * FROM "Estimate" WHERE id = $1 AND organization_id = $2', [item.estimate_id, item.org_id]);
  if (!estResult.rows.length) throw new Error('Estimate not found');
  const estimate = estResult.rows[0];

  const itemsResult = await client.query('SELECT * FROM "EstimateItem" WHERE estimate_id = $1 ORDER BY id', [item.estimate_id]);
  const items = itemsResult.rows;

  return [{ json: { estimate, items, org_id: item.org_id, estimate_id: item.estimate_id } }];
} finally {
  await client.end();
}

