const item = $input.first().json;
const estimate = item.estimate;
const items = item.items;

// Формируем данные для Google Sheet
const rows = [];
rows.push(['Вид работы', 'Материал', 'Единица', 'Количество', 'Цена', 'Стоимость работы', 'Итого']);

for (const ei of items) {
  const materials = typeof ei.materials === 'string' ? JSON.parse(ei.materials) : ei.materials;
  for (let j = 0; j < materials.length; j++) {
    const m = materials[j];
    rows.push([
      j === 0 ? ei.work_type : '',
      m.name,
      m.unit,
      m.quantity,
      m.price,
      j === 0 ? ei.labor_cost : '',
      j === 0 ? ei.total_cost : ''
    ]);
  }
}
rows.push(['', '', '', '', '', 'ИТОГО:', estimate.total_cost]);

// TODO: Заменить на реальный URL после настройки Google Sheets
const sheetUrl = 'https://docs.google.com/spreadsheets/d/PLACEHOLDER_' + item.estimate_id;

return [{ json: { sheet_url: sheetUrl, estimate_id: item.estimate_id, org_id: item.org_id, rows } }];

const { Client } = require('pg');
const item = $input.first().json;
const client = new Client({ host: $env.APP_PG_HOST || 'db', port: parseInt($env.APP_PG_PORT || '5432'), user: $env.APP_PG_USER, password: $env.APP_PG_PASSWORD, database: ($env.APP_PG_DATABASE || 'ragkb_app') });
await client.connect();
try {
  await client.query('UPDATE "Estimate" SET sheet_url = $1, updated_at = NOW() WHERE id = $2', [item.sheet_url, item.estimate_id]);
  return [{ json: { sheet_url: item.sheet_url } }];
} finally {
  await client.end();
}
